  @api wv:bypassed(nodeId)  @ 273
  @api wv:setEdgePrimary(idx, primary)  @ 276-282
      @contract  sets edges[idx].primary via wm:mutate; coerced to true/nil (nil-not-false per DAG).  @ 275
  @api wv:ancestorsOf(sourceId)  @ 287-290
      @contract  backward reachability over user.edges; returns { [id]=true } including sourceId  @ 286
  @api wv:descendantsOf(sourceId)  @ 293-296
      @contract  forward reachability over user.edges; returns { [id]=true } including sourceId  @ 292
  @api wv:wiredPorts(nodeId, dir)  @ 299-309
      @contract  returns { [portIdx]=true } over audio edges on nodeId for dir ('out'|'in'); midi edges ignored  @ 298
  @api wv:masterPos()  @ 312-316
      @contract  logical canvas position of the master node as x, y; 0,0 if master is somehow absent  @ 311
  @api wv:nodeViews()  @ 322-327
      @contract  returns the list of nodeViews for every node in the current user graph; order unspecified (pairs over graph.nodes)  @ 321
  @api wv:busViews()  @ 331-345
      @contract  one busView per buss record; pos/orient from the node when present, else the record  @ 330
  @api wv:wireViews()  @ 357-394
